/*
{CON_DESC}
*/
public void exec_concepto_{CON_CODE}(int idxCargo) 
{
int Error, Periodo;
bool EsManual;  
double Valor, Cantidad;
double ValorManual, CantidadManual;

EsManual=false;
Error=0; Valor=0; Cantidad=0;
ValorManual=0; CantidadManual=0;
Periodo=this.liqddo.Periodo;

//Obtengo el Recibo
Recibos.TOT_LIQ_PER recibo=this.liqAdic.Recibo;
LegajoEmpresaDDO.PER_EMP_DDO legajo=this.liqAdic.Legajo;
LegajoEmpresaDDO.CARGO_DDO cargo=(idxCargo>=0?(LegajoEmpresaDDO.CARGO_DDO)this.liqAdic.Legajo.Cargos[idxCargo]:null);

NomadXML varsXML,concXML;
varsXML=concXML=this.conceptosXML.AddTailElement("CONCEPTO");
concXML.SetAttr("COD"   , "{CON_CODE}");
concXML.SetAttr("DES"   , "{CON_DESC}");
concXML.SetAttr("manual", "0");


//Agrego las Variables	
{CON_VARIN}

 //Concepto MANUAL!!!!
PersonalLiquidacionDDO.CON_MAN_PER_DDO conc_man_per = null;
conc_man_per = (PersonalLiquidacionDDO.CON_MAN_PER_DDO) this.liqAdic.LegajoLiq.ConceptosManuales.GetByAttribute("IDConcepto", "{CON_ID}");
if (conc_man_per != null) 
{
	EsManual = true;
	ValorManual = System.Math.Round(conc_man_per.Valor,{DEC});
	CantidadManual = System.Math.Round(conc_man_per.Cantidad,{DEC});

	concXML.SetAttr("manual", "1");
	trace.Info("El concepto {CON_CODE} se liquido manualmente.");
} else
if ((this.liqddo.LiquidacionAjuste) && (!{CON_AJUSTE}))
{
	//Caso que la liquidacion sea de ajuste y el concepto no se tiene que ejecutar
	return;
}

try
{
	concepto_{CON_CODE}(this.liqAdic.Empresa, this.liqddo, legajo, cargo, this.liqAdic, ref Valor, ref Cantidad, ref Error, ValorManual, CantidadManual, EsManual {CON_PARAMS});

	Valor=System.Math.Round(Valor,{DEC});
	Cantidad=System.Math.Round(Cantidad,{DEC});

	VerificarRango(Valor, "Valor", "{CON_CODE}");
	VerificarRango(Cantidad, "Cantidad", "{CON_CODE}");

//Redondeo Variables
{CON_ROUND}

} catch (Exception e) 
{
	trace.Error("Se produjo un error causado por la ejecucion del codigo del concepto {CON_CODE}: {CON_DESC}. "+e.ToString());
	traceInt.Error("Se produjo un error causado por la ejecucion del codigo del concepto {CON_CODE}: {CON_DESC}. "+e.ToString());
	return;
}

if (!EsManual && Error != 0) 
{
	//existe codigo de Error?
	if (this.decodeError[Error] == null) 
	{
		trace.Error("Valor de Error invalido: Error=" + Error + ". El concepto {CON_CODE}:{CON_DESC} retorno un valor de la variable Error desconocido.");
		traceInt.Error("Valor de Error invalido: Error=" + Error + ". El concepto {CON_CODE}:{CON_DESC} retorno un valor de la variable Error desconocido.");
		return;
	}

	//Agrego el ERROR 
	Recibos.ERROR_LIQ newERR=new Recibos.ERROR_LIQ();
	newERR.oi_concepto_ddo="{CON_ID}";
	newERR.oi_error        =(string)this.decodeError[Error];
	recibo.ERRORES_LIQ.Add(newERR);

	//Error en el concepto
	trace.Error("El Concepto {CON_CODE} genero el Error "+Error);
	traceInt.Error("El Concepto {CON_CODE} genero el Error "+Error);
}

//Modifico el Valor porque es Manual
if (EsManual) 
{
	Valor = ValorManual;
	Cantidad = CantidadManual;
}
concXML.SetAttr("error"   , Error);
concXML.SetAttr("valor"   , Valor);
concXML.SetAttr("cantidad", Cantidad);


//Acumular Variables
{CON_ACUM}

//Actualizo las Variables	
{CON_VAROUT}

//Acumula los valores en el Recibo
AcumularValoresRecibo("{CON_TIPO_CONCEPTO}", "{CON_FIG_RECIBO}", "{CON_ACUM_GANANCIA}", Valor, Cantidad, varsXML);

//Agrego el Concepto al Recibo
Recibos.CONC_LIQ_PER newCONC=(Recibos.CONC_LIQ_PER)recibo.CONC_LIQ_PER.GetByAttribute("oi_concepto_ddo","{CON_ID}");
if (newCONC!=null && Valor==0 && Cantidad==0 && !this.myLiq.l_debug && "{CON_TIPO_CONCEPTO}"!="9")
{ 
	recibo.CONC_LIQ_PER.Remove(newCONC);
} else
if (newCONC!=null || Valor!=0 || Cantidad!=0 || this.myLiq.l_debug || "{CON_TIPO_CONCEPTO}"=="9")
{
	//Genero el Concepto
	if (newCONC==null) 
	{
		newCONC=new Recibos.CONC_LIQ_PER();
		newCONC.oi_concepto_ddo="{CON_ID}";
		newCONC.n_valor        =Valor;
		newCONC.n_cantidad     =Cantidad;
		recibo.CONC_LIQ_PER.Add(newCONC);
	} else
	{
		newCONC.n_valor        =Valor;
		newCONC.n_cantidad     =Cantidad;
	}

	//Agrego Variables al Concepto
	newCONC.VAR_LIQ_CONC.Clear();
	{CON_VARAPPEND}
}
}

